#pragma once

#include <cuda_fp8.h>
#include <cuda_bf16.h>
#include <cuda_runtime.h>
#include <stdint.h>

// Constants from specification
#define HIDDEN_SIZE 7168
#define INTERMEDIATE_SIZE 2048
#define GEMM1_OUT_SIZE 4096
#define NUM_EXPERTS 256
#define NUM_LOCAL_EXPERTS 32
#define BLOCK_SIZE 128
#define TOP_K 8
#define N_GROUP 8
#define TOPK_GROUP 4

// Block counts
#define NUM_HIDDEN_BLOCKS (HIDDEN_SIZE / BLOCK_SIZE)
#define NUM_INTERMEDIATE_BLOCKS (INTERMEDIATE_SIZE / BLOCK_SIZE)
#define NUM_GEMM1_OUT_BLOCKS (GEMM1_OUT_SIZE / BLOCK_SIZE)

// FP8 Type
typedef __nv_fp8_e4m3 fp8_t;

// Kernel Config
struct MoEConfig {
    int seq_len;
    int local_expert_offset;
    float routed_scaling_factor;
};

// Routing Kernel
__global__ void routing_kernel(
    const float* routing_logits,
    const __nv_bfloat16* routing_bias,
    int* topk_indices,
    float* topk_weights,
    int seq_len,
    int num_experts,
    float routed_scaling_factor
);

// MoE Compute Kernel
__global__ void moe_kernel(
    const fp8_t* hidden_states,
    const float* hidden_states_scale,
    const fp8_t* gemm1_weights,
    const float* gemm1_weights_scale,
    const fp8_t* gemm2_weights,
    const float* gemm2_weights_scale,
    const int* topk_indices,
    const float* topk_weights,
    __nv_bfloat16* output,
    int seq_len,
    int num_local_experts,
    int local_expert_offset
);

// Host function
void run_moe(
    const float* routing_logits,
    const __nv_bfloat16* routing_bias,
    const fp8_t* hidden_states,
    const float* hidden_states_scale,
    const fp8_t* gemm1_weights,
    const float* gemm1_weights_scale,
    const fp8_t* gemm2_weights,
    const float* gemm2_weights_scale,
    int* topk_indices,
    float* topk_weights,
    __nv_bfloat16* output,
    int seq_len,
    int local_expert_offset,
    float routed_scaling_factor
);

#include "kernel.h"
#include <device_launch_parameters.h>
#include <math_constants.h>

// Helper: FP8 to FP32 dequantization
__device__ inline float fp8_to_fp32(fp8_t val, float scale) {
    return __nv_fp8_to_float(val) * scale;
}

// Helper: FP32 to BF16
__device__ inline __nv_bfloat16 fp32_to_bf16(float val) {
    return __float2bfloat16(val);
}

// Sigmoid
__device__ inline float sigmoid(float x) {
    return 1.0f / (1.0f + expf(-x));
}

// Silu
__device__ inline float silu(float x) {
    return x / (1.0f + expf(-x));
}

// Routing Kernel
__global__ void routing_kernel(
    const float* routing_logits,
    const __nv_bfloat16* routing_bias,
    int* topk_indices,
    float* topk_weights,
    int seq_len,
    int num_experts,
    float routed_scaling_factor
) {
    int t = blockIdx.x * blockDim.x + threadIdx.x;
    if (t >= seq_len) return;

    float* logits_ptr = routing_logits + t * num_experts;
    int* idx_ptr = topk_indices + t * TOP_K;
    float* w_ptr = topk_weights + t * TOP_K;

    // 1. Sigmoid and Bias
    // Load bias
    float bias_val = __bfloat162float(routing_bias[0]); // Assuming bias broadcasted or handled
    // Actually bias is [num_experts].
    // We need to load bias for each expert.
    // To optimize, load bias into shared memory or registers.
    // Since num_experts=256, we can load into registers.

    // Temporary buffers for computation
    float s[256];
    float s_with_bias[256];
    float group_scores[8];

    // Compute Sigmoid and Add Bias
    for (int e = 0; e < num_experts; ++e) {
        float logit = logits_ptr[e];
        float bias = __bfloat162float(routing_bias[e]);
        float s_val = sigmoid(logit);
        s[e] = s_val;
        s_with_bias[e] = s_val + bias;
    }

    // 2. Grouping and Top-2 Sum
    // N_GROUP = 8, Group Size = 32
    for (int g = 0; g < N_GROUP; ++g) {
        float top1 = -FLT_MAX;
        float top2 = -FLT_MAX;
        int start = g * 32;
        for (int i = 0; i < 32; ++i) {
            float val = s_with_bias[start + i];
            if (val > top1) {
                top2 = top1;
                top1 = val;
            } else if (val > top2) {
                top2 = val;
            }
        }
        group_scores[g] = top1 + top2;
    }

    // 3. Select Top-4 Groups
    int group_idx[4];
    float group_vals[4];
    for (int k = 0; k < TOPK_GROUP; ++k) {
        float max_val = -FLT_MAX;
        int max_g = -1;
        for (int g = 0; g < N_GROUP; ++g) {
            if (group_scores[g] > max_val) {
                max_val = group_scores[g];
                max_g = g;
            }
        }
        group_vals[k] = max_val;
        group_idx[k] = max_g;
        group_scores[max_g] = -FLT_MAX; // Mark as used
    }

    // 4. Global Top-8 within selected groups
    float scores_pruned[256];
    for (int e = 0; e < num_experts; ++e) {
        int g = e / 32;
        bool selected = false;
        for (int k = 0; k < TOPK_GROUP; ++k) {
            if (group_idx[k] == g) {
                selected = true;
                break;
            }
        }
        scores_pruned[e] = selected ? s_with_bias[e] : -FLT_MAX;
    }

    // Select Top-8
    int selected_experts[8];
    float selected_scores[8];
    for (int k = 0; k < TOP_K; ++k) {
        float max_val = -FLT_MAX;
        int max_e = -1;
        for (int e = 0; e < num_experts; ++e) {
            if (scores_pruned[e] > max_val) {
                max_val = scores_pruned[e];
                max_e = e;
            }
        }
        selected_experts[k] = max_e;
        selected_scores[k] = max_val;
        scores_pruned[max_e] = -FLT_MAX;
    }

    // 5. Compute Weights (from s, normalized, scaled)
    float weight_sum = 0.0f;
    float weights_raw[8];
    for (int k = 0; k < TOP_K; ++k) {
        int e = selected_experts[k];
        weights_raw[k] = s[e];
        weight_sum += weights_raw[k];
    }

    float norm_factor = (weight_sum > 0) ? (1.0f / weight_sum) : 0.0f;
    norm_factor *= routed_scaling_factor;

    for (int k = 0; k < TOP_K; ++k) {
        idx_ptr[k] = selected_experts[k];
        w_ptr[k] = weights_raw[k] * norm_factor;
    }
}

// GEMM Helper: FP8 Block Scale
// Computes C += A * B with block scaling
// A: [M, K], B: [K, N], C: [M, N]
// Scales are loaded based on block indices
__device__ void fp8_gemm_tile(
    float* C, // Output [M, N]
    const fp8_t* A, // Input [M, K]
    const float* A_scale, // [M_blocks, T] (simplified access)
    const fp8_t* B, // Weights [K, N]
    const float* B_scale, // [N_blocks, K_blocks]
    int M, int K, int N,
    int M_block_size, int K_block_size, int N_block_size
) {
    // This is a simplified inline implementation for the kernel
    // Full tiling logic is in moe_kernel
}

// MoE Kernel
__global__ void moe_kernel(
    const fp8_t* hidden_states,
    const float* hidden_states_scale,
    const fp8_t* gemm1_weights,
    const float* gemm1_weights_scale,
    const fp8_t* gemm2_weights,
    const float* gemm2_weights_scale,
    const int* topk_indices,
    const float* topk_weights,
    __nv_bfloat16* output,
    int seq_len,
    int num_local_experts,
    int local_expert_offset
) {
    int expert_id = blockIdx.x; // 0 to 31
    if (expert_id >= num_local_experts) return;

    int global_expert_id = local_expert_offset + expert_id;
    if (global_expert_id < 0 || global_expert_id >= NUM_EXPERTS) return;

    // Shared memory for weights tiling
    // W1: [4096, 128] -> 4096 * 128 * 1 = 512KB. Too big for Shared Mem.
    // We stream W1 tiles.
    // We use registers for accumulation.

    // We process tokens in a grid-stride loop
    for (int t = threadIdx.x; t < seq_len; t += blockDim.x) {
        // Check if this token routes to this expert
        const int* tok_indices = topk_indices + t * TOP_K;
        const float* tok_weights = topk_weights + t * TOP_K;

        bool selected = false;
        float weight = 0.0f;
        for (int k = 0; k < TOP_K; ++k) {
            if (tok_indices[k] == global_expert_id) {
                selected = true;
                weight = tok_weights[k];
                break;
            }
        }

        if (!selected) continue;

        // Load Hidden States for token t
        // hidden_states: [T, H]
        // hidden_states_scale: [H/128, T]
        const fp8_t* h_ptr = hidden_states + t * HIDDEN_SIZE;
        const float* h_scale_ptr = hidden_states_scale; // [56, T]

        // GEMM1: A @ W1 -> [4096]
        // A: [7168], W1: [4096, 7168]
        // W1: [E, 4096, 7168]
        const fp8_t* w1_ptr = gemm1_weights + expert_id * GEMM1_OUT_SIZE * HIDDEN_SIZE;
        const float* w1_scale_ptr = gemm1_weights_scale + expert_id * NUM_GEMM1_OUT_BLOCKS * NUM_HIDDEN_BLOCKS;

        float out1[4096] = {0}; // Accumulator

        // Tiled GEMM1
        // K loop (7168)
        for (int k_block = 0; k_block < NUM_HIDDEN_BLOCKS; ++k_block) {
            int k_start = k_block * BLOCK_SIZE;

            // Load Scale for this K-block
            // h_scale: [56, T] -> h_scale[k_block, t]
            float h_scale = h_scale_ptr[k_block * seq_len + t];

            // W1 Scale: [32, 32, 56] -> w1_scale[expert_id, out_block, k_block]
            // We need to iterate out_block too to load W1 tiles
            for (int m_block = 0; m_block < NUM_GEMM1_OUT_BLOCKS; ++m_block) {
                int m_start = m_block * BLOCK_SIZE;
                float w1_scale = w1_scale_ptr[m_block * NUM_HIDDEN_BLOCKS + k_block];
                float combined_scale = h_scale * w1_scale;

                // Compute Tile
                const fp8_t* w1_tile = w1_ptr + m_start * HIDDEN_SIZE + k_start;
                const fp8_t* h_tile = h_ptr + k_start;

                // Inner loop over block elements
                for (int m = 0; m < BLOCK_SIZE; ++m) {
                    float sum = 0.0f;
                    for (int k = 0; k < BLOCK_SIZE; ++k) {
                        sum += fp8_to_fp32(w1_tile[m * HIDDEN_SIZE + k], combined_scale) * 
                               fp8_to_fp32(h_tile[k], 1.0f); // h_scale applied to combined
                        // Correction: h_scale applies to h, w_scale to w.
                        // fp8_to_fp32(w, w_scale) * fp8_to_fp32(h, h_scale)
                    }
                    out1[m_start + m] += sum;
                }
            }
        }

        // SwiGLU
        float intermediate[2048];
        for (int i = 0; i < INTERMEDIATE_SIZE; ++i) {
            float gate = out1[i];
            float up = out1[i + INTERMEDIATE_SIZE];
            intermediate[i] = gate * silu(up);
        }

        // GEMM2: Intermediate @ W2 -> [7168]
        // Intermediate: [2048], W2: [7168, 2048]
        // W2: [E, 7168, 2048]
        const fp8_t* w2_ptr = gemm2_weights + expert_id * HIDDEN_SIZE * INTERMEDIATE_SIZE;
        const float* w2_scale_ptr = gemm2_weights_scale + expert_id * NUM_HIDDEN_BLOCKS * NUM_INTERMEDIATE_BLOCKS;

        float out2[7168] = {0};

        // Tiled GEMM2
        // K loop (2048)
        for (int k_block = 0; k_block < NUM_INTERMEDIATE_BLOCKS; ++k_block) {
            int k_start = k_block * BLOCK_SIZE;

            // W2 Scale: [32, 56, 16] -> w2_scale[expert_id, out_block, k_block]
            for (int m_block = 0; m_block < NUM_HIDDEN_BLOCKS; ++m_block) {
                int m_start = m_block * BLOCK_SIZE;
                float w2_scale = w2_scale_ptr[m_block * NUM_INTERMEDIATE_BLOCKS + k_block];

                const fp8_t* w2_tile = w2_ptr + m_start * INTERMEDIATE_SIZE + k_start;
                const float* inter_tile = intermediate + k_start;

                for (int m = 0; m < BLOCK_SIZE; ++m) {
                    float sum = 0.0f;
                    for (int k = 0; k < BLOCK_SIZE; ++k) {
                        sum += fp8_to_fp32(w2_tile[m * INTERMEDIATE_SIZE + k], w2_scale) * inter_tile[k];
                    }
                    out2[m_start + m] += sum;
                }
            }
        }

        // Accumulate to Output
        // output: [T, H]
        // Use atomicAdd for BF16
        __nv_bfloat16* out_ptr = output + t * HIDDEN_SIZE;
        for (int h = 0; h < HIDDEN_SIZE; ++h) {
            float val = out2[h] * weight;
            // atomicAdd for __nv_bfloat16 is available on Ampere
            // We need to convert to float, atomicAdd, convert back?
            // No, atomicAdd supports __nv_bfloat16 directly in CUDA 11+
            // But we need to load, add, store.
            // atomicAdd(&out_ptr[h], __float2bfloat16(val));
            // Wait, atomicAdd for BF16 takes __nv_bfloat16.
            atomicAdd(&out_ptr[h], __float2bfloat16(val));
        }
    }
}

void run_moe(
    const float* routing_logits,
    const __nv_bfloat16* routing_bias,
    const fp8_t* hidden_states,
    const float* hidden_states_scale,
    const fp8_t* gemm1_weights,
    const float* gemm1_weights_scale,
    const fp8_t* gemm2_weights,
    const float* gemm2_weights_scale,
    int* topk_indices,
    float* topk_weights,
    __nv_bfloat16* output,
    int seq_len,
    int local_expert_offset,
    float routed_scaling_factor
) {
    // Routing Kernel
    int threads = 256;
    int blocks = (seq_len + threads - 1) / threads;
    routing_kernel<<<blocks, threads>>>(
        routing_logits, routing_bias, topk_indices, topk_weights,
        seq_len, NUM_EXPERTS, routed_scaling_factor
    );

    // MoE Kernel
    int moe_blocks = NUM_LOCAL_EXPERTS;
    int moe_threads = 256;
    moe_kernel<<<moe_blocks, moe_threads>>>(
        hidden_states, hidden_states_scale,
        gemm1_weights, gemm1_weights_scale,
        gemm2_weights, gemm2_weights_scale,
        topk_indices, topk_weights,
        output,
        seq_len, NUM_LOCAL_EXPERTS, local_expert_offset
    );
}

#include <torch/extension.h>
#include "kernel.h"
#include <ATen/ATen.h>
#include <ATen/cuda/CUDAContext.h>

void run(
    torch::Tensor routing_logits,
    torch::Tensor routing_bias,
    torch::Tensor hidden_states,
    torch::Tensor hidden_states_scale,
    torch::Tensor gemm1_weights,
    torch::Tensor gemm1_weights_scale,
    torch::Tensor gemm2_weights,
    torch::Tensor gemm2_weights_scale,
    int local_expert_offset,
    float routed_scaling_factor
) {
    // Validate Inputs
    TORCH_CHECK(routing_logits.device().is_cuda(), "routing_logits must be on CUDA");
    TORCH_CHECK(routing_logits.dtype() == torch::kFloat32, "routing_logits must be float32");
    TORCH_CHECK(routing_bias.device().is_cuda(), "routing_bias must be on CUDA");
    TORCH_CHECK(routing_bias.dtype() == torch::kBFloat16, "routing_bias must be bfloat16");
    TORCH_CHECK(hidden_states.device().is_cuda(), "hidden_states must be on CUDA");
    TORCH_CHECK(hidden_states.dtype() == torch::kFloat8_e4m3fn, "hidden_states must be fp8_e4m3fn");
    TORCH_CHECK(hidden_states_scale.device().is_cuda(), "hidden_states_scale must be on CUDA");
    TORCH_CHECK(hidden_states_scale.dtype() == torch::kFloat32, "hidden_states_scale must be float32");
    TORCH_CHECK(gemm1_weights.device().is_cuda(), "gemm1_weights must be on CUDA");
    TORCH_CHECK(gemm1_weights.dtype() == torch::kFloat8_e4m3fn, "gemm1_weights must be fp8_e4m3fn");
    TORCH_CHECK(gemm1_weights_scale.device().is_cuda(), "gemm1_weights_scale must be on CUDA");
    TORCH_CHECK(gemm1_weights_scale.dtype() == torch::kFloat32, "gemm1_weights_scale must be float32");
    TORCH_CHECK(gemm2_weights.device().is_cuda(), "gemm2_weights must be on CUDA");
    TORCH_CHECK(gemm2_weights.dtype() == torch::kFloat8_e4m3fn, "gemm2_weights must be fp8_e4m3fn");
    TORCH_CHECK(gemm2_weights_scale.device().is_cuda(), "gemm2_weights_scale must be on CUDA");
    TORCH_CHECK(gemm2_weights_scale.dtype() == torch::kFloat32, "gemm2_weights_scale must be float32");

    int seq_len = routing_logits.size(0);
    int num_experts = routing_logits.size(1);
    TORCH_CHECK(num_experts == 256, "num_experts must be 256");

    // Allocate Temporary Buffers
    auto topk_indices = torch::empty({seq_len, TOP_K}, torch::kInt32, routing_logits.device());
    auto topk_weights = torch::empty({seq_len, TOP_K}, torch::kFloat32, routing_logits.device());
    auto output = torch::zeros({seq_len, HIDDEN_SIZE}, torch::kBFloat16, routing_logits.device());

    // Launch Kernel
    run_moe(
        routing_logits.data_ptr<float>(),
        routing_bias.data_ptr<__nv_bfloat16>(),
        hidden_states.data_ptr<__nv_fp8_e4m3>(),
        hidden_states_scale.data_ptr<float>(),
        gemm1_weights.data_ptr<__nv_fp8_e4m3>(),
        gemm1_weights_scale.data_ptr<float>(),
        gemm2_weights.data_ptr<__nv_fp8_e4m3>(),
        gemm2_weights_scale.data_ptr<float>(),
        topk_indices.data_ptr<int>(),
        topk_weights.data_ptr<float>(),
        output.data_ptr<__nv_bfloat16>(),
        seq_len,
        local_expert_offset,
        routed_scaling_factor
    );

    // Return output
    // Note: In a real extension, we would return the output tensor.
    // Here we assume the function is void and modifies output in place or returns it via reference.
    // Since the spec says "Outputs: output", we return it.
    // But the signature in run is void. Let's modify run to return torch::Tensor.
}

torch::Tensor run_func(
    torch::Tensor routing_logits,
    torch::Tensor routing_bias,
    torch::Tensor hidden_states,
    torch::Tensor hidden_states_scale,
    torch::Tensor gemm1_weights,
    torch::Tensor gemm1_weights_scale,
    torch::Tensor gemm2_weights,
    torch::Tensor gemm2_weights_scale,
    int local_expert_offset,
    float routed_scaling_factor
) {
    // Validate Inputs
    TORCH_CHECK(routing_logits.device().is_cuda(), "routing_logits must be on CUDA");
    TORCH_CHECK(routing_logits.dtype() == torch::kFloat32, "routing_logits must be float32");
    TORCH_CHECK(routing_bias.device().is_cuda(), "routing_bias must be on CUDA");
    TORCH_CHECK(routing_bias.dtype() == torch::kBFloat16, "routing_bias must be bfloat16");
    TORCH_CHECK(hidden_states.device().is_cuda(), "hidden_states must be on CUDA");
    TORCH_CHECK(hidden_states.dtype() == torch::kFloat8_e4m3fn, "hidden_states must be fp8_e4m3fn");
    TORCH_CHECK(hidden_states_scale.device().is_cuda(), "hidden_states_scale must be on CUDA");
    TORCH_CHECK(hidden_states_scale.dtype() == torch::kFloat32, "hidden_states_scale must be float32");
    TORCH_CHECK(gemm1_weights.device().is_cuda(), "gemm1_weights must be on CUDA");
    TORCH_CHECK(gemm1_weights.dtype() == torch::kFloat8_e4m3fn, "gemm1_weights must be fp8_e4m3fn");
    TORCH_CHECK(gemm1_weights_scale.device().is_cuda(), "gemm1_weights_scale must be on CUDA");
    TORCH_CHECK(gemm1_weights_scale.dtype() == torch::kFloat32, "gemm1_weights_scale must be float32");
    TORCH_CHECK(gemm2_weights.device().is_cuda(), "gemm2_weights must be on CUDA");
    TORCH_CHECK(gemm2_weights.dtype() == torch::kFloat8_e4m3fn, "gemm2_weights must be fp8_e4m3fn");
    TORCH_CHECK(gemm2_weights_scale.device().is_cuda(), "gemm2_weights_scale must be on CUDA");
    TORCH_CHECK(gemm2_weights_scale.dtype() == torch::kFloat32, "gemm2_weights_scale must be float32");

    int seq_len = routing_logits.size(0);
    int num_experts = routing_logits.size(1);
    TORCH_CHECK(num_experts == 256, "num_experts must be 256");

    // Allocate Temporary Buffers
    auto topk_indices = torch::empty({seq_len, TOP_K}, torch::kInt32, routing_logits.device());
    auto topk_weights = torch::empty({seq_len, TOP_K}, torch::kFloat32, routing_logits.device());
    auto output = torch::zeros({seq_len, HIDDEN_SIZE}, torch::kBFloat16, routing_logits.device());

    // Launch Kernel
    run_moe(
        routing_logits.data_ptr<float>(),
        routing_bias.data_ptr<__nv_bfloat16>(),
        hidden_states.data_ptr<__nv_fp8_e4m3>(),
        hidden_states_scale.data_ptr<float>(),
        gemm1_weights.data_ptr<__nv_fp8_e4m3>(),
        gemm1_weights_scale.data_ptr<float>(),
        gemm2_weights.data_ptr<__nv_fp8_e4m3>(),
        gemm2_weights_scale.data_ptr<float>(),
        topk_indices.data_ptr<int>(),
        topk_weights.data_ptr<float>(),
        output.data_ptr<__nv_bfloat16>(),
        seq_len,
        local_expert_offset,
        routed_scaling_factor
    );

    return output;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run_func, "MoE Kernel execution function");
}
